parameters.jsCode:
const txt = $json.content?.[0]?.text || '{}';
let e = {};
try { e = JSON.parse(txt); } catch (err) {
  const m = txt.match(/\{[\s\S]*\}/); if (m) { try { e = JSON.parse(m[0]); } catch(_){} }
}
const src = $('Split Leads').item.json;
return [{ json: {
  recordId: src.id,
  companyEmail: src.fields.Email,
  companyName: src.fields.Name,
  language: e.language || 'en',
  subject: e.subject || ('Partnership with ' + ($env.ORG_NAME||'us')),
  body: (e.body || '') + '\n\n' + ($env.SENDER_SIGNATURE || '').replace(/\\n/g,'\n')
}}];
